    const N_A = Math.floor(N / 2);
    const A = nums.slice(0, N_A);
    const B = nums.slice(N_A);

    // Step 3: Generate maps for both halves
    const mapA = generateMap(A);
    const mapB = generateMap(B);

    // Step 4: Combine results to find minimum removed count
